// Legislação Portuguesa - Código do Trabalho
// Período normal de trabalho: 8 horas/dia, 40 horas/semana
// Horas extras:
// - Primeiras 2 horas: +25%
// - Horas seguintes: +37.5%
// - Dias de descanso/feriados: +50%

export const DAILY_HOURS = 8;
export const DAILY_MINUTES = DAILY_HOURS * 60; // 480 minutos
export const WEEKLY_HOURS = 40;
export const WEEKLY_MINUTES = WEEKLY_HOURS * 60; // 2400 minutos

// Taxas de horas extras (em Portugal)
export const OVERTIME_RATES = {
  first_two_hours: 0.25, // +25% para as primeiras 2 horas
  additional_hours: 0.375, // +37.5% para as seguintes
  rest_days: 0.50, // +50% em dias de descanso
};

export function parseTime(timeStr) {
  if (!timeStr) return null;
  const [hours, minutes] = timeStr.split(':').map(Number);
  return hours * 60 + minutes;
}

export function formatMinutesToTime(totalMinutes) {
  if (totalMinutes === null || totalMinutes === undefined) return '--:--';
  const hours = Math.floor(totalMinutes / 60);
  const minutes = Math.round(totalMinutes % 60);
  return `${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}`;
}

export function formatMinutesToHoursDecimal(totalMinutes) {
  if (!totalMinutes) return '0.00';
  return (totalMinutes / 60).toFixed(2);
}

export function calculateDailyWorkMinutes(record) {
  if (!record) return { total: 0, overtime: 0 };

  let totalMinutes = 0;

  // Turno 1
  const t1Entrada = parseTime(record.turno1_entrada);
  const t1Saida = parseTime(record.turno1_saida);
  if (t1Entrada !== null && t1Saida !== null) {
    totalMinutes += Math.max(0, t1Saida - t1Entrada);
  }

  // Turno 2
  const t2Entrada = parseTime(record.turno2_entrada);
  const t2Saida = parseTime(record.turno2_saida);
  if (t2Entrada !== null && t2Saida !== null) {
    totalMinutes += Math.max(0, t2Saida - t2Entrada);
  }

  // Calcular horas extras (acima de 8 horas = 480 minutos)
  const overtimeMinutes = Math.max(0, totalMinutes - DAILY_MINUTES);

  return {
    total: totalMinutes,
    overtime: overtimeMinutes,
  };
}

export function calculateOvertimePay(overtimeMinutes, hourlyRate = 0) {
  if (!overtimeMinutes || overtimeMinutes <= 0) return 0;

  const overtimeHours = overtimeMinutes / 60;
  let pay = 0;

  if (overtimeHours <= 2) {
    // Primeiras 2 horas: +25%
    pay = overtimeHours * hourlyRate * (1 + OVERTIME_RATES.first_two_hours);
  } else {
    // Primeiras 2 horas: +25%
    pay = 2 * hourlyRate * (1 + OVERTIME_RATES.first_two_hours);
    // Horas seguintes: +37.5%
    pay += (overtimeHours - 2) * hourlyRate * (1 + OVERTIME_RATES.additional_hours);
  }

  return pay;
}

export function calculateWeeklyStats(records) {
  const totalMinutes = records.reduce((sum, r) => sum + (r.total_minutes || 0), 0);
  const totalOvertime = records.reduce((sum, r) => sum + (r.overtime_minutes || 0), 0);
  
  return {
    totalMinutes,
    totalOvertime,
    totalHours: totalMinutes / 60,
    overtimeHours: totalOvertime / 60,
    daysWorked: records.filter(r => r.total_minutes > 0).length,
  };
}

export function calculateMonthlyStats(records) {
  const totalMinutes = records.reduce((sum, r) => sum + (r.total_minutes || 0), 0);
  const totalOvertime = records.reduce((sum, r) => sum + (r.overtime_minutes || 0), 0);
  
  return {
    totalMinutes,
    totalOvertime,
    totalHours: totalMinutes / 60,
    overtimeHours: totalOvertime / 60,
    daysWorked: records.filter(r => r.total_minutes > 0).length,
  };
}